1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	type Step = QuoteStep;
14	
15	interface Scenario {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	}
19	
20	const BASE_PREMIUM: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	};
27	
28	const FIRST_INSURANCE_RATE = 0.1;
29	const CURSE_RATE = 0.5;
30	const HIGH_ENCH_RATE = 0.3;
31	const HIGH_ENCH_THRESHOLD = 5;
32	const LOYALTY_RATE = 0.2;
33	const LOYALTY_THRESHOLD = 2;
34	const PROCESSING_FEE = 5;
35	
36	const COMPONENT_PREMIUM = 25;
37	const BLOCK_SIZE = 3;
38	const BLOCK_PREMIUM = 60;
39	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
40	
41	const componentBasePremium = (count: number): number =>
42	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
43	
44	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
45	
46	const isMainItem = (item: Item): boolean => !isComponent(item);
47	
48	const countByType = (items: Item[]): Map<string, number> =>
49	  items.reduce(
50	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
51	    new Map<string, number>(),
52	  );
53	
54	const componentTotal = (items: Item[]): number =>
55	  [...countByType(items.filter(isComponent)).values()].reduce(
56	    (sum, count) => sum + componentBasePremium(count),
57	    0,
58	  );
59	
60	const basePremium = (items: Item[]): number => {
61	  const mainTotal = items
62	    .filter(isMainItem)
63	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
64	  return mainTotal + componentTotal(items);
65	};
66	
67	const mainItemBase = (item: Item): number => BASE_PREMIUM[item.type];
68	
69	const surchargeFor = (
70	  items: Item[],
71	  qualifies: (item: Item) => boolean,
72	  rate: number,
73	): number =>
74	  items
75	    .filter((item) => isMainItem(item) && qualifies(item))
76	    .reduce((sum, item) => sum + mainItemBase(item) * rate, 0);
77	
78	const isCursed = (item: Item): boolean => item.cursed === true;
79	
80	const curseSurcharge = (items: Item[]): number =>
81	  surchargeFor(items, isCursed, CURSE_RATE);
82	
83	const isHighlyEnchanted = (item: Item): boolean =>
84	  (item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD;
85	
86	const highEnchantmentSurcharge = (items: Item[]): number =>
87	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCH_RATE);
88	
89	const loyaltyDiscount = (policyBase: number, years: number): number =>
90	  years >= LOYALTY_THRESHOLD ? policyBase * LOYALTY_RATE : 0;
91	
92	const quotePremium = (items: Item[], years: number): number => {
93	  const policyBase = basePremium(items);
94	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
95	  const itemSurcharges = curseSurcharge(items) + highEnchantmentSurcharge(items);
96	  const loyalty = loyaltyDiscount(policyBase, years);
97	  return Math.ceil(
98	    policyBase + itemSurcharges + firstInsurance - loyalty + PROCESSING_FEE,
99	  );
100	};
101	
102	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
103	  const years = scenario.customer.yearsWithMHPCO;
104	  const results = scenario.steps.map((step) => ({
105	    premium: quotePremium(step.items, years),
106	  }));
107	  return { results };
108	};
